+                            //   builder: (context) =>
+                            //        NewsDetailScreen(news: news),
+                            //   ),
+                            //     );
+                            // Ação ao tocar no item da lista
+                          },
+                        ),
+                        const Divider(
+                          height: 1,
+                          thickness: 1,
+                          color: Colors
+                              .grey, // Ou use CustomColors().getTextColor()
